mapper.select:
SELECT TM_ID, SSNT_YR, MKT_SZ, PPLT_RTG, FAN_LYLTY, FAN_EXP,
       REG_INTRST, NATNL_PPLT, MRCH_PWR, AVG_ATND_CNT, SSNT_TCKT_HLDR
FROM TM_MKT_SSNT
WHERE TM_ID = #{tmId}
  AND SSNT_YR = #{ssntYr}

SELECT COUNT(*)
FROM TM_FCLTY_UPGR
WHERE TM_ID = #{tmId}
  AND FCLTY_TYPE_CD = #{fcltyTypeCd}
  AND UPGR_STTS_CD = 'PROG'

mapper.update:
UPDATE TM_FCLTY
   SET FCLTY_LVL = #{newLvl}
 WHERE TM_ID = #{tmId}
   AND FCLTY_TYPE_CD = #{fcltyTypeCd}

UPDATE STDM
   SET STDM_SEAT_CNT = #{seatCnt}
 WHERE STDM_ID = #{stdmId}
